{
  "family": "Ritter Reaction",
  "candidate": {
    "substrate_smiles": [
      "CC(C)(C)O",
      "CC#N"
    ],
    "product_smiles": [
      "CC(=O)NC(C)(C)C"
    ],
    "optional_reagent_smiles": [
      "O=S(=O)(O)O"
    ],
    "rationale": "This reaction is a classic textbook example of the Ritter reaction. Tert-butanol is protonated by sulfuric acid and loses water to form a stable tert-butyl carbocation. This carbocation is then attacked by the nitrogen of acetonitrile, forming a nitrilium ion intermediate. Subsequent hydrolysis yields N-tert-butylacetamide. The reactants are simple, acyclic, and clearly demonstrate the core transformation: the conversion of a carbocation source (alcohol) and a nitrile into an N-alkyl amide.",
    "collision_avoidance_note": "This example uses simple, acyclic, saturated aliphatic substrates (tert-butanol and acetonitrile) to avoid overlap with other named reactions. It avoids arenes (Friedel-Crafts), complex ring systems, or other functional groups that could trigger unrelated reaction classifiers. The core transformation is clearly the formation of an N-alkyl amide from a nitrile and a carbocation source, which is the defining feature of the Ritter reaction."
  }
}
